mistake_patterns.detection_sql:
-- Check if spine and data share the same grain:
SELECT typeof(day) FROM (SELECT generate_series('2024-01-01', '2024-01-07', INTERVAL '1 day') AS day) LIMIT 1;
SELECT typeof(order_date) FROM orders LIMIT 1;

-- Compare spine size to data size:
SELECT COUNT(*) AS spine_rows FROM (SELECT generate_series('2020-01-01', '2024-12-31', INTERVAL '1 day') AS day);
SELECT COUNT(DISTINCT DATE_TRUNC('day', order_date)) AS data_days FROM orders;

-- Verify spine length matches expected gap count:
SELECT COUNT(*) FROM date_spine;
SELECT COUNT(*) FROM (SELECT s.day FROM date_spine s LEFT JOIN daily_orders o ON s.day = o.day WHERE o.day IS NULL);
